import React from 'react';
import WebPageLogo from '../Logo/GnuLinuxLogo.svg';
import WebPageHeaderInfoBackgroundImage from '../Background/WebPageHeaderInfoBackgroundImage.jpg';
import WebPageHeaderInfoGitHubLogo from '../Logo/GitHubLogo.svg';

import '../WebPageHeaderInfo.css';

class WebPageHeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || WebPageLogo,
      currentPageName: props.currentPageName || '',
      backgroundImage: props.backgroundImage || WebPageHeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || WebPageHeaderInfoGitHubLogo,
      githubURL: props.githubURL || "www.github.com",
      githubPagesURL: props.githubPagesURL || "www.github.com",
      domainName: props.domainName || "www.unix69.githubio.com",
      pageName: props.pageName || "Unix69",
      webPageHeaderInfoClass: props.webPageHeaderInfoClass || "web-page-header-info",
      webPageHeaderInfoBackgroundImageClass: props.webPageHeaderInfoBackgroundImageClass || "web-page-header-info-background-image",
      webPageHeaderInfoDomainInfoClass: props.webPageHeaderInfoDomainInfoClass || "web-page-header-info-domain-info",
      webPageHeaderInfoDomainLogoClass: props.webPageHeaderInfoDomainLogoClass || "web-page-header-info-domain-logo",
      webPageHeaderInfoGitHubInfoClass: props.webPageHeaderInfoGitHubInfoClass || "web-page-header-info-github-info",
      webPageHeaderInfoGitHubLogoClass: props.webPageHeaderInfoGitHubLogoClass || "web-page-header-info-github-logo"
    };
  }

  render() {
    return (<section>
                  <img src={this.state.domainLogo} alt="Domain Logo" class={this.state.webPageHeaderInfoDomainLogoClass}/>
                  <a href={this.state.domainName} class={this.state.webPageHeaderInfoDomainLogoClass}>{this.state.pageName}</a>
                  {this.state.currentPageName}   
                  <a href={this.state.githubURL} class={this.state.webPageHeaderInfoDomainLogoClass}/>
                  <img src={this.state.githubLogo} alt="GitHub Logo" class={this.state.webPageHeaderInfoGitHubLogoClass}/>
                  <a href={this.state.githubPagesURL} class={this.state.webPageHeaderInfoGitHubInfoClass}>Git Hub Pages</a>
            </section>
    );
  }
}

export default WebPageHeaderInfo;
